1	import { useMemo, useEffect, useRef, useState, useCallback } from "react";
2	import { useMarkets, useMarket, useEngineStats } from "@/lib/query/hooks";
3	import { formatProbability } from "@/lib/utils/format";
4	import { useAssumptions } from "@/features/assumptions/AssumptionContext";
5	import { useAnimationPropagation } from "./useAnimationPropagation";
6	import { deriveEdgesFromCliques, mergeEdges } from "./deriveEdges";
7	import { buildNetworkExport, downloadJson } from "./networkExport";
8	import { readAndValidateFile } from "./networkImport";
9	import type { NetworkExportSchema } from "./networkExportSchema";
10	import type { MarketSummary } from "@/lib/api/types";
11	
12	interface GraphNode {
13	  id: string;
14	  title: string;
15	  x: number;
16	  y: number;
17	  marginals: Record<string, number>;
18	  outcomeName: string;
19	  status: string;
20	}
21	
22	interface GraphEdge {
23	  from: string;
24	  to: string;
25	  label?: string;
26	}
27	
28	interface BayesNetGraphProps {
29	  /** The currently viewed market — highlighted in the graph */
30	  focusMarketId?: string;
31	  /** Edges derived from conditional edits */
32	  conditionalEdges?: GraphEdge[];
33	}
34	
35	const NODE_W = 160;
36	const NODE_H = 72;
37	const PADDING = 60;
38	
39	function layoutNodes(markets: MarketSummary[]): GraphNode[] {
40	  // Arrange in a circle for small N, grid for larger
41	  const n = markets.length;
42	  if (n === 0) return [];
43	
44	  const cx = 300;
45	  const cy = 200;
46	  const radius = Math.max(120, n * 40);
47	
48	  return markets.map((m, i) => {
49	    const angle = (2 * Math.PI * i) / n - Math.PI / 2;
50	    return {
51	      id: m.id,
52	      title: m.title.length > 28 ? m.title.slice(0, 26) + "…" : m.title,
53	      x: cx + radius * Math.cos(angle),
54	      y: cy + radius * Math.sin(angle),
55	      marginals: {},
56	      outcomeName: "",
57	      status: m.status,
58	    };
59	  });
60	}
61	
62	function MarketNode({
63	  node,
64	  isFocus,
65	  detail,
66	  animationClass,
67	}: {
68	  node: GraphNode;
69	  isFocus: boolean;
70	  detail?: { marginals: Record<string, number>; outcomes: Array<{ id: string; name: string }> };
71	  animationClass?: string;
72	}) {
73	  const borderColor = isFocus ? "var(--color-primary)" : "var(--color-border)";
74	  const bg = isFocus ? "var(--color-bg-surface)" : "var(--color-bg)";
75	
76	  return (
77	    <g
78	      transform={`translate(${node.x - NODE_W / 2}, ${node.y - NODE_H / 2})`}
79	      className={animationClass}
80	    >
81	      <rect
82	        width={NODE_W}
83	        height={NODE_H}
84	        rx={8}
85	        fill={bg}
86	        stroke={borderColor}
87	        strokeWidth={isFocus ? 2.5 : 1}
88	      />
89	      <text
90	        x={NODE_W / 2}
91	        y={18}
92	        textAnchor="middle"
93	        fontSize="11"
94	        fontWeight={600}
95	        fill="var(--color-text)"
96	      >
97	        {node.title}
98	      </text>
99	      {/* Mini probability bars */}
100	      {detail && detail.outcomes.length > 0 && (
101	        <g transform="translate(8, 28)">
102	          {detail.outcomes.slice(0, 3).map((o, i) => {
103	            const p = detail.marginals[o.id] ?? 0;
104	            const barW = NODE_W - 16;
105	            return (
106	              <g key={o.id} transform={`translate(0, ${i * 14})`}>
107	                <rect width={barW} height={10} rx={3} fill="var(--color-border)" opacity={0.3} />
108	                <rect
109	                  width={Math.max(2, barW * p)}
110	                  height={10}
111	                  rx={3}
112	                  fill={animationClass ? "var(--color-info)" : p > 0.5 ? "var(--color-success)" : "var(--color-info)"}
113	                  opacity={animationClass ? 0.9 : 0.7}
114	                  style={{ transition: "width 0.3s ease, opacity 0.3s ease, fill 0.3s ease" }}
115	                />
116	                <text x={4} y={8} fontSize="8" fill="var(--color-text)" fontWeight={500}>
117	                  {o.name}: {formatProbability(p)}
118	                </text>
119	              </g>
120	            );
121	          })}
122	        </g>
123	      )}
124	      {/* Status dot */}
125	      <circle
126	        cx={NODE_W - 10}
127	        cy={10}
128	        r={4}
129	        fill={
130	          node.status === "active"
131	            ? "var(--color-success)"
132	            : node.status === "resolved"
133	              ? "var(--color-info)"
134	              : "var(--color-text-muted)"
135	        }
136	      />
137	    </g>
138	  );
139	}
140	
141	function EdgeLine({ from, to, nodes }: { from: string; to: string; nodes: GraphNode[] }) {
142	  const a = nodes.find((n) => n.id === from);
143	  const b = nodes.find((n) => n.id === to);
144	  if (!a || !b) return null;
145	
146	  // Arrow from a → b
147	  const dx = b.x - a.x;
148	  const dy = b.y - a.y;
149	  const dist = Math.sqrt(dx * dx + dy * dy);
150	  if (dist === 0) return null;
151	
152	  const ux = dx / dist;
153	  const uy = dy / dist;
154	
155	  // Start/end offset by node radius
156	  const startX = a.x + ux * (NODE_W / 2 + 4);
157	  const startY = a.y + uy * (NODE_H / 2 + 4);
158	  const endX = b.x - ux * (NODE_W / 2 + 8);
159	  const endY = b.y - uy * (NODE_H / 2 + 8);
160	
161	  return (
162	    <g>
163	      <line
164	        x1={startX}
165	        y1={startY}
166	        x2={endX}
167	        y2={endY}
168	        stroke="var(--color-primary)"
169	        strokeWidth={1.5}
170	        strokeDasharray="6 3"
171	        opacity={0.6}
172	      />
173	      {/* Arrowhead */}
174	      <polygon
175	        points={`${endX},${endY} ${endX - ux * 8 - uy * 4},${endY - uy * 8 + ux * 4} ${endX - ux * 8 + uy * 4},${endY - uy * 8 - ux * 4}`}
176	        fill="var(--color-primary)"
177	        opacity={0.6}
178	      />
179	    </g>
180	  );
181	}
182	
183	function CliqueOverlay({
184	  clique,
185	  nodes,
186	}: {
187	  clique: { id: string; nodes: string[] };
188	  nodes: GraphNode[];
189	}) {
190	  const memberNodes = nodes.filter((n) => clique.nodes.includes(n.id));
191	  if (memberNodes.length < 2) return null;
192	
193	  // Draw a rounded rectangle around the clique members
194	  const xs = memberNodes.map((n) => n.x);
195	  const ys = memberNodes.map((n) => n.y);
196	  const pad = 20;
197	  const minX = Math.min(...xs) - NODE_W / 2 - pad;
198	  const minY = Math.min(...ys) - NODE_H / 2 - pad;
199	  const maxX = Math.max(...xs) + NODE_W / 2 + pad;
200	  const maxY = Math.max(...ys) + NODE_H / 2 + pad;
201	
202	  return (
203	    <g>
204	      <rect
205	        x={minX}
206	        y={minY}
207	        width={maxX - minX}
208	        height={maxY - minY}
209	        rx={12}
210	        fill="var(--color-primary)"
211	        fillOpacity={0.06}
212	        stroke="var(--color-primary)"
213	        strokeWidth={1}
214	        strokeDasharray="4 4"
215	        strokeOpacity={0.3}
216	      />
217	      <text x={minX + 6} y={minY + 14} fontSize="9" fill="var(--color-primary)" opacity={0.7}>
218	        Clique {clique.id}
219	      </text>
220	    </g>
221	  );
222	}
223	
