28	      </div>
29	    );
30	  }
31	
32	  if (!cptData) return null;
33	
34	  const { outcomes, parents, entries } = cptData;
35	  const hasParents = parents.length > 0;
36	
37	  const handleCellClick = (entryIndex: number, outcomeId: string, currentP: number) => {
38	    if (!isConfigured) return;
39	    setEditing({ entryIndex, outcomeId, probability: currentP });
40	  };
41	
42	  const handleSubmit = () => {
43	    if (!editing || !cptData) return;
44	    const entry = entries[editing.entryIndex];
45	    if (!entry) return;
46	
47	    mutation.mutate(
48	      {
49	        payload: {
50	          accountId: session.accountId,
51	          variableId: market.variableId,
52	          target: {
53	            kind: "marginal",
54	            outcomeId: editing.outcomeId,
55	            probability: editing.probability,
56	          },
57	          context: entry.context,
58	          idempotencyKey: crypto.randomUUID(),
59	        },
60	        session,
61	      },
62	      {
63	        onSuccess: () => setEditing(null),
64	      },
65	    );
66	  };
67	
68	  const handleCancel = () => setEditing(null);
69	
70	  return (
71	    <div style={panelStyle}>
72	      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "var(--space-sm)" }}>
