77	        </span>
78	      </div>
79	
80	      {!hasParents && (
81	        <p style={{ fontSize: "0.8rem", color: "var(--color-text-muted)", marginBottom: "var(--space-sm)" }}>
82	          No parent variables — showing marginal probabilities.
83	        </p>
84	      )}
85	
86	      <div style={{ borderRadius: "var(--radius-md)", border: "1px solid var(--color-border)", overflow: "hidden" }}>
87	        <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.8rem" }}>
88	          <thead>
89	            <tr style={{ background: "var(--color-bg-hover)" }}>
90	              {hasParents && <th style={thStyle}>Condition</th>}
91	              {outcomes.map((o) => (
92	                <th key={o.id} style={thStyle}>P({o.name})</th>
93	              ))}
94	            </tr>
95	          </thead>
96	          <tbody>
97	            {entries.map((entry, entryIdx) => (
98	              <tr key={entry.contextKey || "__marginal"} style={{ borderTop: "1px solid var(--color-border)" }}>
99	                {hasParents && (
100	                  <td style={{ ...tdStyle, fontFamily: "var(--font-mono)", fontSize: "0.75rem" }}>
101	                    {entry.context.map((c) => {
102	                      const parent = parents.find((p) => p.variableId === c.variableId);
103	                      const outcomeName = parent?.outcomes.find((o) => o.id === c.outcomeId)?.name ?? c.outcomeId;
104	                      const parentName = parent?.title ?? c.variableId;
105	                      return `${parentName}=${outcomeName}`;
106	                    }).join(", ")}
107	                  </td>
108	                )}
109	                {outcomes.map((o) => {
110	                  const p = entry.marginals[o.id] ?? 0;
111	                  const isEditing = editing?.entryIndex === entryIdx && editing?.outcomeId === o.id;
112	
113	                  if (isEditing) {
114	                    return (
115	                      <td key={o.id} style={tdStyle}>
116	                        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
117	                          <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
118	                            <input
119	                              type="range"
120	                              min={0.01}
121	                              max={0.99}
122	                              step={0.01}
123	                              value={editing.probability}
124	                              onChange={(e) => setEditing({ ...editing, probability: Number(e.target.value) })}
125	                              style={{ flex: 1, minWidth: 60 }}
126	                            />
127	                            <span style={{ fontFamily: "var(--font-mono)", fontSize: "0.75rem", minWidth: 40 }}>
128	                              {formatProbability(editing.probability)}
129	                            </span>
130	                          </div>
131	                          <div style={{ display: "flex", gap: 4 }}>
132	                            <button
133	                              onClick={handleSubmit}
134	                              disabled={mutation.isPending}
135	                              style={setBtnStyle}
136	                            >
137	                              {mutation.isPending ? "..." : "Set"}
138	                            </button>
139	                            <button onClick={handleCancel} style={cancelBtnStyle}>Cancel</button>
140	                          </div>
141	                        </div>
142	                      </td>
143	                    );
144	                  }
145	
146	                  return (
147	                    <td
148	                      key={o.id}
149	                      style={{
150	                        ...tdStyle,
151	                        fontFamily: "var(--font-mono)",
152	                        cursor: isConfigured ? "pointer" : "default",
153	                        position: "relative",
154	                      }}
155	                      onClick={() => handleCellClick(entryIdx, o.id, p)}
156	                    >
157	                      <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
158	                        <div style={{
159	                          width: 40,
160	                          height: 6,
161	                          borderRadius: 3,
162	                          background: "var(--color-border)",
163	                          overflow: "hidden",
164	                        }}>
165	                          <div style={{
166	                            width: `${Math.max(2, p * 100)}%`,
167	                            height: "100%",
168	                            borderRadius: 3,
169	                            background: p > 0.5 ? "var(--color-success)" : "var(--color-info)",
170	                          }} />
171	                        </div>
172	                        <span>{formatProbability(p)}</span>
173	                      </div>
174	                    </td>
175	                  );
176	                })}
177	              </tr>
178	            ))}
179	          </tbody>
180	        </table>
181	      </div>
182	
183	      {mutation.isSuccess && (
184	        <div style={successStyle}>
185	          Edit accepted: {mutation.data.order.orderId}
186	        </div>
187	      )}
188	
189	      {mutation.isError && (
190	        <div style={errorStyle}>
191	          {mutation.error instanceof Error ? mutation.error.message : "Edit failed"}
192	        </div>
193	      )}
194	
195	      {!isConfigured && (
196	        <p style={{ fontSize: "0.75rem", color: "var(--color-text-muted)", marginTop: "var(--space-sm)" }}>
197	          Set your Account ID to edit probabilities.
198	        </p>
199	      )}
200	    </div>
201	  );
202	}
